using Ledgerly.Domain.Entities; using Ledgerly.Domain.Enums; using Ledgerly.Domain.ValueObjects; namespace Ledgerly.Domain.Tests; public class BillTests { static readonly CurrencyCode Usd=new("USD"); static readonly Guid Org=Guid.NewGuid(),Vendor=Guid.NewGuid(),Exp=Guid.NewGuid(),Ap=Guid.NewGuid(),Tax=Guid.NewGuid(); [Fact] public void Approve_sets_approved(){ var b=new Bill(Org,Vendor,"BILL-1",new DateOnly(2026,3,1),new DateOnly(2026,3,31),Usd,Exp,Ap); b.AddLine("Supplies",1m,new Money(100m,Usd),Tax,new Money(0m,Usd)); b.Approve(new Dictionary<Guid,decimal>{{Tax,0.1m}}); Assert.Equal(BillStatus.Approved,b.Status); Assert.Equal(110m,b.TotalAmount.Amount);} [Fact] public void RecordPayment_paid(){ var b=new Bill(Org,Vendor,"BILL-2",new DateOnly(2026,3,1),new DateOnly(2026,3,31),Usd,Exp,Ap); b.AddLine("Supplies",1m,new Money(100m,Usd),null,new Money(0m,Usd)); b.Approve(new Dictionary<Guid,decimal>()); b.RecordPayment(new Money(100m,Usd)); Assert.Equal(BillStatus.Paid,b.Status);} }
